def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    accum = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    accum *= np.sin(ratio * b / (a + 2))
                    priority += accum
            priority += (np.exp(ratio - 7) * np.cos(ratio * 1.3)) ** 2 + np.tanh(ratio)
        elif 5 < ratio <= 7:
            for c in range(1, int(np.ceil(ratio)) + 4):
                for d in range(1, c + 3):
                    factor = ((ratio - c) ** 4) * np.cos(ratio * c) / (d + 0.7)
                    priority += np.tanh(factor) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            if bin_cap < item * 1.4:
                priority += np.sqrt(item * bin_cap) * 2
            else:
                priority -= np.exp(-0.5 * ratio)
        elif 2 <= ratio <= 5:
            s = 0
            for e in range(1, 15):
                s += ((ratio - 2) ** e) / (e * 2.2) * np.sin(e * ratio)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (5 - ratio)) * 2
            for f in range(1, 6):
                priority += np.cos(f * ratio * i) * ((ratio - 1.9) ** f) / f
            if bin_cap > item * 1.8:
                priority -= np.exp(-ratio) * 4
        elif 1 <= ratio < 2:
            s = 0
            for g in range(1, 12):
                s += ((2 - ratio) ** g) / (g ** 2 + 1) * np.tanh(g * ratio * 0.8)
            if bin_cap < item * 0.9:
                penalty = np.log1p(item / (bin_cap + 1)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for h in range(1, 7):
                priority += np.sin(h * ratio * i) * ((ratio - 0.9) ** h) / (h + 1)
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 18):
                s += ((1 - ratio) ** j) / (j * 3)
            priority = s
            if ((i + int(item * 2)) % 5) == 1:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for k in range(1, 9):
                priority += ((1 - ratio) ** k) * np.sin(k * item * 1.8) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 14):
                s += ((0.5 - ratio) ** l) / (l * 4) * np.cos(l * ratio * 3)
            priority = s + 1 / (bin_cap + 5)
            if int(item * 1.5) % 7 == 2:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 8):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.4)
            if bin_cap > item * 2:
                priority -= np.exp(-0.8 * ratio) * 2.5
        elif 0.05 <= ratio < 0.2:
            s = 0
            for n in range(1, 15):
                s += ((0.2 - ratio) ** n) / (n * 5) * np.sin(n * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 6 == 1:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.12:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for o in range(1, 9):
                priority += ((0.2 - ratio) ** o) / (o * 8) * np.cos(item * o * 0.7)
            if bin_cap < item * 0.5:
                priority += np.sqrt(bin_cap + 1) * 2
        else:
            s = 0
            for p in range(1, 12):
                s += ((0.05 - ratio) ** p) / (p * 6) * np.cos(p * item * 0.95)
            priority = s + 4 / (bin_cap + 7)
            if int(item * 0.8) % 8 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for q in range(1, 10):
                priority += ((0.05 - ratio) ** q) / (q * 9) * np.sin(item * q * 0.85)
            if bin_cap > item * 3:
                priority -= np.exp(-ratio) * 3
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if i % 2 == 0 and bin_cap > item:
            priority += np.tanh(ratio * i) * 1.1
        else:
            priority -= np.tanh(ratio * (i + 1)) * 1.1
        priorities[i] = priority
    return priorities
